"""
Tower of Hanoi - Solution Demo
Load a trained agent and watch it solve the puzzle.
"""

import sys
import os
import time
from main import HanoiTower, QLearningAgent

# Try to import PyTorch for DQN
try:
    import torch
    from main import DQNAgent, device
    PYTORCH_AVAILABLE = True
except ImportError:
    PYTORCH_AVAILABLE = False


def solve_with_qlearning(filename: str, num_disks: int, show_moves: bool = False):
    """
    Load Q-Learning agent and solve the puzzle.
    
    Args:
        filename: Path to saved Q-Learning agent
        num_disks: Number of disks
        show_moves: Whether to show each move
    """
    print("\n" + "="*60)
    print("Loading Q-Learning Agent...")
    print("="*60)
    
    # Load agent
    agent = QLearningAgent()
    agent.load(filename)
    
    # Create environment
    env = HanoiTower(num_disks)
    state = env.reset()
    
    print(f"\nSolving {num_disks}-disk Tower of Hanoi...")
    print("="*60)
    
    # Show initial state
    env.render()
    
    if show_moves:
        input("\nPress Enter to start solving...")
    
    # Solve
    done = False
    optimal_moves = 2**num_disks - 1
    max_steps = optimal_moves * 3
    steps = 0
    
    while not done and steps < max_steps:
        valid_actions = env.get_valid_actions()
        action = agent.get_action(state, valid_actions, training=False)
        state, reward, done, _ = env.step(action)
        steps += 1
        
        if show_moves:
            env.render()
            if not done:
                time.sleep(0.5)  # Pause between moves
    
    if not show_moves:
        print("\n" + "="*60)
        print("Final state:")
        print("="*60)
        env.render()
    
    # Results
    print(f"\n{'='*60}")
    if done:
        print(f"✅ Puzzle solved in {env.moves} moves!")
        print(f"   Optimal solution: {optimal_moves} moves")
        print(f"   Efficiency: {optimal_moves/env.moves*100:.1f}%")
        if env.moves == optimal_moves:
            print(f"   ⭐⭐⭐ PERFECT SOLUTION! ⭐⭐⭐")
        elif env.moves <= optimal_moves * 1.5:
            print(f"   ⭐⭐ Great solution!")
        else:
            print(f"   ⭐ Good solution!")
    else:
        print(f"❌ Failed to solve within {max_steps} moves")
    print(f"{'='*60}\n")


