def list_saved_agents():
    """List all saved agent files in current directory."""
    import glob
    
    qlearn_files = glob.glob("hanoi_qlearn_*.pkl")
    dqn_files = glob.glob("hanoi_dqn_*.pth")
    legacy_files = glob.glob("hanoi_agent_*.pkl")
    
    print("\nAvailable trained agents:")
    print("-" * 60)
    
    if qlearn_files or legacy_files:
        print("\nQ-Learning agents (.pkl):")
        for f in qlearn_files + legacy_files:
            print(f"  - {f}")
    
    if dqn_files:
        print("\nDQN agents (.pth):")
        for f in dqn_files:
            print(f"  - {f}")
    
    if not (qlearn_files or dqn_files or legacy_files):
        print("  No saved agents found.")
        print("  Train an agent first using main.py")
    
    print("-" * 60)


def main():
    """Main function to demonstrate trained agent solutions."""
    print("Tower of Hanoi - Solution Demo")
    print("="*60)
    print("Watch a trained agent solve the puzzle!")
    print("="*60)
    
    # List available agents
    list_saved_agents()
    
    # Choose agent type
    print("\nAgent types:")
    print("  1. Q-Learning (.pkl file)")
    if PYTORCH_AVAILABLE:
        print("  2. DQN (.pth file)")
    else:
        print("  2. DQN - NOT AVAILABLE (install torch)")
    
    choice = input("\nSelect agent type (1 or 2): ").strip()
    
    # Get filename and disk count
    filename = input("Enter agent filename (or press Enter for default): ").strip()
    num_disks = int(input("Number of disks (default=5): ").strip() or "5")
    
    show_moves = input("Show each move? (y/n, default=n): ").strip().lower() == 'y'
    
    # Solve based on choice
    if choice == "1":
        if not filename:
            filename = f"hanoi_qlearn_{num_disks}disks.pkl"
            if not os.path.exists(filename):
                filename = f"hanoi_agent_{num_disks}disks.pkl"  # Try legacy name
        
        if not os.path.exists(filename):
            print(f"\n❌ File not found: {filename}")
            print("   Train an agent first using main.py")
            return
        
        solve_with_qlearning(filename, num_disks, show_moves)
        
    elif choice == "2":
        if not PYTORCH_AVAILABLE:
            print("\n❌ PyTorch not available! Install with: pip install torch")
            return
        
        if not filename:
            filename = f"hanoi_dqn_{num_disks}disks.pth"
        
        if not os.path.exists(filename):
            print(f"\n❌ File not found: {filename}")
            print("   Train a DQN agent first using main.py")
            return
        
        solve_with_dqn(filename, num_disks, show_moves)
    
    else:
        print("Invalid choice!")


if __name__ == "__main__":
    main()
